const now = new Date();
const from = new Date(now.getTime() - 6 * 60 * 1000); // last 6 min (small overlap)
return [{ json: {
  startDate: from.toISOString(),
  endDate:   now.toISOString()
} }];

const VALID_CATEGORIES = [
  'New Complaint',
  'Vendor Reply',
  'Store Reply',
  'Quotation / Invoice',
  'FM / HO Communication',
  'Business Opportunity',
  'Auto Response',
  'Others'
];

const results = [];

for (const item of items) {
  const email = item.json;
  const cats  = email.categories || [];

  // Skip if already has a valid auto-category
  const alreadyCategorized = cats.some(c => VALID_CATEGORIES.includes(c));
  if (alreadyCategorized) continue;

  const subject  = (email.subject       || '(no subject)').slice(0, 200);
  const preview  = (email.bodyPreview    || '').slice(0, 400);
  const sender   = email.from?.emailAddress?.address || '';

  const aiPrompt = 'Email Subject: ' + subject + '\nSender: ' + sender + '\nBody Preview: ' + preview;

  results.push({ json: {
    emailId:  email.id,
    subject,
    sender,
    aiPrompt
  }});
}

if (!results.length) return [{ json: { skip: true } }];
return results;

const VALID_CATEGORIES = [
  'New Complaint',
  'Vendor Reply',
  'Store Reply',
  'Quotation / Invoice',
  'FM / HO Communication',
  'Business Opportunity',
  'Auto Response',
  'Others'
];

const aiResponse = $input.first().json;
const raw = (
  aiResponse.message?.content ||
  aiResponse.choices?.[0]?.message?.content ||
  aiResponse.text ||
  ''
).trim();

// Match to valid category (case-insensitive)
const category = VALID_CATEGORIES.find(
  c => c.toLowerCase() === raw.toLowerCase()
) || 'Others';

const prev = $('Filter & Prep Prompt').first().json;

return [{ json: {
  emailId:  prev.emailId,
  subject:  prev.subject,
  category,
  rawAI:    raw
} }];
